<?php
// Generated by Cursor prompt — module: Izin (LeaveType) — date: 2026-03-15

namespace App\Modules\Izin\Models;

use Illuminate\Database\Eloquent\Model;
use Illuminate\Database\Eloquent\SoftDeletes;
use Illuminate\Database\Eloquent\Relations\BelongsTo;
use Illuminate\Database\Eloquent\Relations\HasMany;

class LeaveType extends Model
{
    use SoftDeletes;

    protected $table = 'leave_types';

    protected $fillable = [
        'company_id',
        'name',
        'paid',
        'max_annual_days',
        'accrual_rule',
        'requires_approval',
        'is_active',
    ];

    protected $casts = [
        'paid'              => 'boolean',
        'requires_approval' => 'boolean',
        'is_active'         => 'boolean',
        'max_annual_days'   => 'decimal:2',
        'accrual_rule'      => 'array',
    ];

    public function company(): BelongsTo
    {
        return $this->belongsTo(\App\Modules\Sirket\Models\Company::class);
    }

    public function leaveRequests(): HasMany
    {
        return $this->hasMany(LeaveRequest::class);
    }

    public function leaveBalances(): HasMany
    {
        return $this->hasMany(LeaveBalance::class);
    }

    public function scopeForCompany($query, int $companyId)
    {
        return $query->where('company_id', $companyId);
    }

    public function scopeActive($query)
    {
        return $query->where('is_active', true);
    }

    /** Personelin bu izin türü için güncel bakiyesini getir */
    public function balanceFor(int $personelId, int $year = 0): ?LeaveBalance
    {
        return $this->leaveBalances()
            ->where('personel_id', $personelId)
            ->where('year', $year ?: now()->year)
            ->first();
    }
}
